#include <stdio.h>
#include <string.h>
#define MAX 1000
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[MAX + 1];
        scanf("%s", s);
        int n = strlen(s);
        int minOps = n * 2;
        char minPalin[MAX + 1];
        for (int len = 0; len <= n; len++) {
            for (int i = 0; i <= n - len; i++) {
                char t[MAX + 1];
                strcpy(t, s);
                for (int j = 0; j < len; j++) {
                    t[i + j] = 'l';
                    t[n - 1 - (i + j)] = 'l';
                }
                int ops = 0;
                for (int j = 0; j < n; j++) {
                    if (t[j] != s[j]) {
                        ops++;
                    }
                }
                if (ops < minOps && strstr(t, "lucky") != NULL) {
                    minOps = ops;
                    strcpy(minPalin, t);
                }
            }
        }
        if (minOps == n * 2) {
            printf("unlucky\n");
        } else {
            printf("%s %d\n", minPalin, minOps);
        }
    }
    return 0;
}

