import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String s = sc.nextLine();
            int n = s.length();
            int minOps = n * 2;
            String minPalin = "";
            for (int len = 0; len <= n; len++) {
                for (int i = 0; i <= n - len; i++) {
                    StringBuilder t = new StringBuilder(s);
                    for (int j = 0; j < len; j++) {
                        t.setCharAt(i + j, 'l');
                        t.setCharAt(n - 1 - (i + j), 'l');
                    }
                    int ops = 0;
                    for (int j = 0; j < n; j++) {
                        if (t.charAt(j) != s.charAt(j)) {
                            ops++;
                        }
                    }
                    if (ops < minOps && t.indexOf("lucky") != -1) {
                        minOps = ops;
                        minPalin = t.toString();
                    }
                }
            }
            if (minOps == n * 2) {
                System.out.println("unlucky");
            } else {
                System.out.println(minPalin + " " + minOps);
            }
        }
    }
}

